"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[9777],{64641:e=>{e.exports=JSON.parse('{"functions":[{"name":"SegmentSize","desc":"Starting sub-segment length in studs. Smaller values produce more raycasts\\nper frame and better thin-surface detection at the cost of performance.\\nThe adaptive system adjusts this value at runtime.\\n\\nDefault: `0.5`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":471,"path":"docs/SubBuilders.lua"}},{"name":"FrameBudget","desc":"Target wall-clock budget in milliseconds this cast may spend on sub-segment\\nraycasts per frame. The adaptive system scales segment size up or down to\\nstay near this target.\\n\\nDefault: `4`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":483,"path":"docs/SubBuilders.lua"}},{"name":"AdaptiveScale","desc":"Multiplier applied when coarsening or refining segment size adaptively.\\nMust be `> 1`. Higher values adapt faster but with less precision.\\n\\nDefault: `1.5`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":494,"path":"docs/SubBuilders.lua"}},{"name":"MinSegmentSize","desc":"Hard floor for adaptive segment size reduction in studs.\\nMust be `<= SegmentSize`. Prevents the adaptive algorithm from shrinking\\nsegments to near-zero.\\n\\nDefault: `0.1`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":506,"path":"docs/SubBuilders.lua"}},{"name":"MaxBouncesPerFrame","desc":"Maximum bounces allowed across all sub-segments within a single frame step.\\nPrevents a bullet from exhausting its entire lifetime bounce budget in one\\nframe when moving very fast through a dense environment.\\n\\nDefault: `10`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":518,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":525,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"HighFidelityBuilder","desc":"Sub-builder for high-fidelity raycasting configuration. Opened via\\n[BehaviorBuilder:HighFidelity]. Call `:Done()` to return to the root\\n[BehaviorBuilder].\\n\\nHigh-fidelity mode subdivides each frame\'s travel into multiple smaller\\nraycasts to prevent fast bullets from tunnelling through thin surfaces.\\nThe segment size is adjusted adaptively each frame to stay near the\\nconfigured frame budget.","source":{"line":459,"path":"docs/SubBuilders.lua"}}')}}]);